SELECT u.username, mr.review_text
FROM users u
INNER JOIN model_reviews mr ON u.user_id = mr.user_id;

SELECT user_id
FROM models
WHERE number_of_regressors = (SELECT MAX(number_of_regressors) FROM models);

SELECT COUNT(DISTINCT user_id) AS Active_Model_Creators
FROM models
WHERE status = 'active';

SELECT review_text, review_date
FROM model_reviews
WHERE model_id = 0;
